  ('aboriginal-f0899a01-moex-00441', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '下列何者非屬行政法之法源？', '["兒童權利公約", "緊急命令", "委辦規則", "預算案"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "86c821c6be4c", "answer_pdf_sha1": "b3a415d6eb0d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00442', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政法一般法律原則之敘述，下列何者正確？', '["行政法之一般法律原則對於行政機關無強制拘束力", "僅限於特定行政法領域有其適用", "憲法原則與行政法一般法律原則並不相容", "部分行政法之一般法律原則明文規定於行政程序法中"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "86c821c6be4c", "answer_pdf_sha1": "b3a415d6eb0d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00443', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於法律保留原則之敘述，下列何者錯誤？', '["基於民主原則，重要事項應經國會民主程序予以決定", "人民之基本權應受保障，非依法律或法律授權，不得加以限制", "基於法治國家原則，國家與人民之關係應由法律予以規定", "給付行政不適用法律保留原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "86c821c6be4c", "answer_pdf_sha1": "b3a415d6eb0d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00444', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政裁量之敘述，下列何者錯誤？', '["行政機關之目的在於追求個案正義，所以訂定抽象一般性裁量準則是不被允許的", "行政機關在特定情況下，原本法律所賦予之裁量權可能發生裁量權限縮至零的情形", "對於行政機關裁量權之違法行使，得透過法院進行司法監督", "行政機關逾越法律所規定之處罰金額上限，一般學理上稱為裁量權之逾越"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "86c821c6be4c", "answer_pdf_sha1": "b3a415d6eb0d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00445', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於「公權力行為」與「私經濟行為」之敘述，下列何者錯誤？', '["行政機關購置行政業務所需之物品，為公權力行為", "衛生福利部中央健康保險署與醫事服務機構締結之特約，為公權力行為", "國宅之出租或出售契約，為私經濟行為", "自來水公司提供全國用水供應，為私經濟行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "86c821c6be4c", "answer_pdf_sha1": "b3a415d6eb0d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
